/// Trait for handling Notification domain events
///
/// All handler methods receive the event sequence number for tracking
/// which events have been processed by the projector.
#[async_trait]
pub trait NotificationEventHandler: Send + Sync {
    /// Handle entity created event
    async fn on_created(&self, event: NotificationCreatedEvent, sequence: i64) -> Result<()>;
    /// Handle entity updated event
    async fn on_updated(&self, event: NotificationUpdatedEvent, sequence: i64) -> Result<()>;
    /// Handle entity deleted event
    async fn on_deleted(&self, event: NotificationDeletedEvent, sequence: i64) -> Result<()>;
}

