/// Repository for Notification projections
#[async_trait]
pub trait NotificationProjectionRepository: Send + Sync {
    async fn save(&self, projection: &NotificationProjection) -> Result<()>;
    async fn find_by_id(&self, id: uuid::Uuid) -> Result<Option<NotificationProjection>>;
    async fn delete(&self, id: uuid::Uuid) -> Result<()>;
    async fn rebuild_all(&self) -> Result<u64>;
}

