/// Projector that updates Notification projection from events
pub struct NotificationProjector<R: NotificationProjectionRepository> {
    repository: Arc<R>,
}

impl<R: NotificationProjectionRepository> NotificationProjector<R> {
    /// Create a new projector
    pub fn new(repository: Arc<R>) -> Self {
        Self { repository }
    }

    /// Rebuild all projections from event history
    pub async fn rebuild(&self) -> Result<u64> {
        self.repository.rebuild_all().await
    }

    /// Process a stored event from the event store
    ///
    /// This method dispatches the event to the appropriate handler based on event type.
    /// Returns Ok(true) if the event was processed, Ok(false) if it was skipped.
    pub async fn process_stored_event(&self, event: &crate::infrastructure::event_store::StoredEvent) -> Result<bool>
    where
        Self: NotificationEventHandler,
    {
        let sequence = event.sequence;

        match event.event_type.as_str() {
            "NotificationCreatedEvent" => {
                let created: NotificationCreatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_created(created, sequence).await?;
                Ok(true)
            }
            "NotificationUpdatedEvent" => {
                let updated: NotificationUpdatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_updated(updated, sequence).await?;
                Ok(true)
            }
            "NotificationDeletedEvent" => {
                let deleted: NotificationDeletedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_deleted(deleted, sequence).await?;
                Ok(true)
            }
            _ => Ok(false), // Event type not handled by this projector
        }
    }
}

#[async_trait]
impl<R: NotificationProjectionRepository> NotificationEventHandler for NotificationProjector<R> {

    async fn on_created(&self, event: NotificationCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = NotificationProjection::new(
            event.id,
            event.user_id,
            event.notification_type,
            event.channel,
            event.title,
            event.message,
            event.data,
            event.is_read,
            event.read_at,
            event.sent_at,
            event.delivered_at,
            event.expires_at,
            event.priority,
            event.action_url,
            event.action_text,
            event.category,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: NotificationUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.notification_type = event.notification_type;
            projection.channel = event.channel;
            projection.title = event.title;
            projection.message = event.message;
            projection.data = event.data;
            projection.is_read = event.is_read;
            projection.read_at = event.read_at;
            projection.sent_at = event.sent_at;
            projection.delivered_at = event.delivered_at;
            projection.expires_at = event.expires_at;
            projection.priority = event.priority;
            projection.action_url = event.action_url;
            projection.action_text = event.action_text;
            projection.category = event.category;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: NotificationDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

